package main

import (
	"sort"
)

type DSU struct {
	parent []int64
	rank   []int64
}

func NewDSU(c int64) *DSU {
	parent := make([]int64, c+1)
	rank := make([]int64, c+1)
	for i := int64(1); i <= c; i++ {
		parent[i] = i
		rank[i] = 1
	}
	return &DSU{parent, rank}
}

func (d *DSU) Find(x int64) int64 {
	if d.parent[x] != x {
		d.parent[x] = d.Find(d.parent[x])
	}
	return d.parent[x]
}

func (d *DSU) Union(x, y int64) {
	xRoot := d.Find(x)
	yRoot := d.Find(y)
	if xRoot == yRoot {
		return
	}
	if d.rank[xRoot] < d.rank[yRoot] {
		d.parent[xRoot] = yRoot
	} else {
		d.parent[yRoot] = xRoot
		if d.rank[xRoot] == d.rank[yRoot] {
			d.rank[xRoot]++
		}
	}
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	dsu := NewDSU(c)
	for _, conn := range connections {
		u := conn[0]
		v := conn[1]
		dsu.Union(u, v)
	}

	componentMap := make(map[int64][]int64)
	for i := int64(1); i <= c; i++ {
		root := dsu.Find(i)
		componentMap[root] = append(componentMap[root], i)
	}

	for key := range componentMap {
		sort.Slice(componentMap[key], func(i, j int) bool {
			return componentMap[key][i] < componentMap[key][j]
		})
	}

	componentMinMap := make(map[int64]int64)
	for key, stations := range componentMap {
		if len(stations) == 0 {
			continue
		}
		componentMinMap[key] = stations[0]
	}

	online := make([]bool, int(c)+1)
	for i := 1; i <= int(c); i++ {
		online[i] = true
	}

	result := []int64{}
	for _, q := range queries {
		if q[0] == 1 {
			x := q[1]
			if online[x] {
				result = append(result, x)
			} else {
				root := dsu.Find(x)
				if componentMinMap[root] == -1 {
					result = append(result, -1)
				} else {
					result = append(result, componentMinMap[root])
				}
			}
		} else {
			x := q[1]
			online[x] = false
			root := dsu.Find(x)
			if componentMinMap[root] == x {
				stations := componentMap[root]
				new_min := -1
				for i := 0; i < len(stations); i++ {
					if online[stations[i]] {
						new_min = stations[i]
						break
					}
				}
				componentMinMap[root] = new_min
			}
		}
	}

	return result
}
